import sys

class Solution:
    def nthRoot(self, num: float, root: int, precision: int) -> float:
        if num < 0:
            return -1
        if num == 0:
            return 0
        left, right = 0, max(1, int(num))
        while right - left > 10**-precision:
            mid = (left + right) / 2
            if pow(mid, root) < num:
                left = mid
            else:
                right = mid
        return round((left + right) / 2, precision)

