#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
double nthRoot(double num, int root, int precision) {
    if (num < 0) return -1;
    if (num == 0) return 0;
    double left = 0, right = max(1.0, num);
    while (right - left > pow(10, -precision)) {
        double mid = (left + right) / 2;
        if (pow(mid, root) < num) {
            left = mid;
        } else {
            right = mid;
        }
    }
    return round((left + right) / 2 * pow(10, precision)) / pow(10, precision);
}
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    double num;
    cin >> num;
    int root;
    cin >> root;
    int precision;
    cin >> precision;
    Solution sol;
    double ans = sol.nthRoot(num, root, precision);
    cout << fixed << setprecision(precision) << ans << '\n';
    return 0;
}
